      ? new Policy(name, ...this.rules.map((rule) => rule.clone()))
      : new Policy(name, ...this.rules)
  }

  /** Static constructor function; returns a new Policy. */
  static for (name: string, ...rules: Rule[]): Policy {
    return new Policy(name, ...rules)
  }
}

